  "business_expectations": [
    {
      "expectation_id": "意图标签识别为客户画像",
      "downstream_consumer": "营销计划生成模块",
      "user_intent": "用户想要分析上季度购买了重疾险的客户画像",
      "expected_outcome": "意图识别接口返回意图为customer_portrait",
      "required_capabilities": ["意图分类"],
      "acceptance_criteria": [
        {
          "field": "intent",
          "expected": "customer_portrait",
          "operator": "eq"
        }
      ],
      "boundary": {
        "scope": "单轮意图识别"
      },
      "priority": "high",
      "evidence_refs": []
    },
    {
      "expectation_id": "目标实体提取为重疾险",
      "downstream_consumer": "客户画像分析模块",
      "user_intent": "用户明确提到了产品“重疾险”",
      "expected_outcome": "target_value字段应为“重疾险”",
      "required_capabilities": ["实体提取"],
      "acceptance_criteria": [
        {
          "field": "target_value",
          "expected": "重疾险",
          "operator": "eq"
        }
      ],
      "boundary": {
        "scope": "单轮意图识别"
      },
      "priority": "high",
      "evidence_refs": []
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "意图标签识别为客户画像",
      "status": "not_fulfilled",
      "score": 0,
      "expected_evidence": [
        {
          "field": "intent",
          "value": "customer_portrait"
        }
      ],
      "actual_evidence": [
        {
          "field": "intent",
          "value": "other"
        }
      ],
      "downstream_impact": "意图错误将导致下游无法启动客户画像分析，计划生成中断",
      "blocking": true,
      "confidence": null,
      "evidence_refs": [
        {
          "stage": "adapter_extraction",
          "field": "intent"
        }
      ]
    },
    {
      "expectation_id": "目标实体提取为重疾险",
      "status": "not_fulfilled",
      "score": 0,
      "expected_evidence": [
        {
          "field": "target_value",
          "value": "重疾险"
        }
      ],
      "actual_evidence": [
        {
          "field": "target_value",
          "value": null
        }
      ],
      "downstream_impact": "无法定位具体产品，导致客户画像分析目标不明确",
      "blocking": true,
      "confidence": null,
      "evidence_refs": [
        {
          "stage": "adapter_extraction",
          "field": "target_value"
        }
      ]
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled",
    "summary": "意图识别未将用户查询识别为客户画像意图，且未提取出关键实体“重疾险”，整体不满足业务要求。"
  },
  "expected": {
    "intent": "customer_portrait",
    "target_value": "重疾险"
  },
  "missing": [],
  "wrong": [
    {
      "kind": "intent_label",
      "error_type": "wrong_intent",
      "expected": "customer_portrait",
      "actual": "other",
      "evidence_ref": "extracted_output.intent",
      "raw": null,
      "incomplete": false
    },
    {
      "kind": "target_value",
      "error_type": "missing_target_value",
      "expected": "重疾险",
      "actual": null,
      "evidence_ref": "extracted_output.target_value",
      "raw": null,
      "incomplete": false
    }
  ],
  "extra": [],
  "evidence": [
    {
      "source": "run_trace.extracted_output",
      "data": {
        "intent": "other",
        "confidence": 0.5,
        "target_value": null,
        "subIntent": "其他意图"
      }
    }
  ],
  "reasoning_summary": "用户查询是“帮我看看上季度买了重疾险的客户都是啥样的？”，明确要求分析购买重疾险的客户画像。预期意图应为customer_portrait，且应提取目标实体“重疾险”。然而，实际意图识别返回了“other”意图，置信度仅为0.5，target_value为null。意图分类错误和实体缺失将导致下游营销计划生成无法正确进行客户画像分析，因此该轮意图识别未满足业务预期。"
}

